[DataContractAttribute]
public class ETGLedgerVoucherExportContract implements SysOperationValidatable
{
    TransDate fromDate;
    TransDate toDate;
    NoYes     filterByCreatedDate;
    NoYes     isIncremental;

}

Method.Source:
[DataMemberAttribute('FromDate'),
 SysOperationLabelAttribute(literalStr("From Date")),
 SysOperationHelpTextAttribute(literalStr("Start date for the manual load")),
 SysOperationDisplayOrderAttribute('1')]
public TransDate parmFromDate(TransDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

[DataMemberAttribute('ToDate'),
 SysOperationLabelAttribute(literalStr("To Date")),
 SysOperationHelpTextAttribute(literalStr("End date for the manual load")),
 SysOperationDisplayOrderAttribute('2')]
public TransDate parmToDate(TransDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

[DataMemberAttribute('FilterByCreatedDate'),
 SysOperationLabelAttribute(literalStr("Filter by Created Date")),
 SysOperationHelpTextAttribute(literalStr("Filter by Created Date instead of Accounting Date")),
 SysOperationDisplayOrderAttribute('3')]
public NoYes parmFilterByCreatedDate(NoYes _filterByCreatedDate = filterByCreatedDate)
{
    filterByCreatedDate = _filterByCreatedDate;
    return filterByCreatedDate;
}

[DataMemberAttribute('IsIncremental'),
 SysOperationLabelAttribute(literalStr("Incremental Load (Daily Batch)")),
 SysOperationHelpTextAttribute(literalStr("If Yes, runs for T-1 (Yesterday). Ignores date parameters.")),
 SysOperationDisplayOrderAttribute('4')]
public NoYes parmIsIncremental(NoYes _isIncremental = isIncremental)
{
    isIncremental = _isIncremental;
    return isIncremental;
}

public boolean validate()
{
    boolean isValid = true;

    // If not incremental, we need dates. If incremental, we ignore dates.
    if (!isIncremental)
    {
        if (!fromDate)
        {
            isValid = checkFailed("From date is required for manual load.");
        }

        if (!toDate)
        {
            isValid = checkFailed("To date is required for manual load.");
        }

        if (fromDate && toDate && fromDate > toDate)
        {
            isValid = checkFailed("From date cannot be greater than to date.");
        }
    }

    return isValid;
}
